changeSet.sql:
CREATE TABLE vacancy_view (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    vacancy_id INTEGER NOT NULL,
    viewer_id INTEGER,
    visitor_key VARCHAR(128),
    viewed_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_vacancy_view_vacancy FOREIGN KEY (vacancy_id) REFERENCES vacancy(id) ON DELETE CASCADE,
    CONSTRAINT fk_vacancy_view_user FOREIGN KEY (viewer_id) REFERENCES users(id) ON DELETE SET NULL
);

CREATE UNIQUE INDEX ux_vacancy_view_user
ON vacancy_view (vacancy_id, viewer_id)
WHERE viewer_id IS NOT NULL;

CREATE UNIQUE INDEX ux_vacancy_view_guest
ON vacancy_view (vacancy_id, visitor_key)
WHERE viewer_id IS NULL AND visitor_key IS NOT NULL;

CREATE INDEX ix_vacancy_view_vacancy
ON vacancy_view (vacancy_id);

CREATE INDEX ix_vacancy_view_viewer
ON vacancy_view (viewer_id);

CREATE TABLE candidate_resume_view (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    resume_id BIGINT NOT NULL,
    viewer_id INTEGER,
    visitor_key VARCHAR(128),
    viewed_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_candidate_resume_view_resume FOREIGN KEY (resume_id) REFERENCES candidate_resume(id) ON DELETE CASCADE,
    CONSTRAINT fk_candidate_resume_view_user FOREIGN KEY (viewer_id) REFERENCES users(id) ON DELETE SET NULL
);

CREATE UNIQUE INDEX ux_candidate_resume_view_user
ON candidate_resume_view (resume_id, viewer_id)
WHERE viewer_id IS NOT NULL;

CREATE UNIQUE INDEX ux_candidate_resume_view_guest
ON candidate_resume_view (resume_id, visitor_key)
WHERE viewer_id IS NULL AND visitor_key IS NOT NULL;

CREATE INDEX ix_candidate_resume_view_resume
ON candidate_resume_view (resume_id);

CREATE INDEX ix_candidate_resume_view_viewer
ON candidate_resume_view (viewer_id);
